fn inorder(node: &Option<Box<TreeNode>>, result: &mut Vec<i32>) {
    if let Some(n) = node {
        inorder(&n.left, result);
        result.push(n.val);
        inorder(&n.right, result);
    }
}

fn preorder(node: &Option<Box<TreeNode>>, result: &mut Vec<i32>) {
    if let Some(n) = node {
        result.push(n.val);
        preorder(&n.left, result);
        preorder(&n.right, result);
    }
}

