struct TreeNode {
    val: i32,
    left: Option<Box<TreeNode>>,
    right: Option<Box<TreeNode>>,
}

impl TreeNode {
    fn new(val: i32) -> Self {
        TreeNode { val, left: None, right: None }
    }
}

fn max_depth(node: &Option<Box<TreeNode>>) -> i32 {
    match node {
        None => 0,
        Some(n) => 1 + std::cmp::max(max_depth(&n.left), max_depth(&n.)),
    }
}

fn main() {
    let mut root = TreeNode::new(1);
    root.left = Some(Box::new(TreeNode::new(2)));
    root.left.as_mut().unwrap().left = Some(Box::new(TreeNode::new(4)));
    root.left.as_mut().unwrap().left.as_mut().unwrap().left = Some(Box::new(TreeNode::new(8)));
    root.right = Some(Box::new(TreeNode::new(3)));

    let root = Some(Box::new(root));
    println!("{}", max_depth(&root));
}
